(function(){
  if (window.__origFetch) return 'already-overridden';
  window.__testDialogAnswer = null;
  window.__origFetch   = window.fetch;
  window.__origPrompt  = window.prompt;
  window.__origConfirm = window.confirm;
  window.__origAlert   = window.alert;
  window.fetch = function(url, opts) {
    if (typeof url === 'string' && url.includes('/api/shell/openFileDialog')) {
      return Promise.resolve({ ok: true, json: () => Promise.resolve({ success: true, path: window.__testDialogAnswer ?? '' }) });
    }
    return window.__origFetch.apply(this, arguments);
  };
  window.prompt  = function(msg, def) { return window.__testDialogAnswer ?? def ?? ''; };
  window.confirm = function() { return true; };
  window.__testAlertMessage = null;
  window.alert   = function(msg) { window.__testAlertMessage = msg; };
  return 'overridden';
})()

(function(){
  if (window.__origFetch)   { window.fetch   = window.__origFetch;   delete window.__origFetch; }
  if (window.__origPrompt)  { window.prompt  = window.__origPrompt;  delete window.__origPrompt; }
  if (window.__origConfirm) { window.confirm = window.__origConfirm; delete window.__origConfirm; }
  if (window.__origAlert)   { window.alert   = window.__origAlert;   delete window.__origAlert; }
  delete window.__testDialogAnswer;
  delete window.__testAlertMessage;
  return 'restored';
})()
